# ----------------------------
# Safe, consistent DB location (fixes “tickets not showing”)
# ----------------------------
DB_PATH = str(Path(__file__).resolve().parent / "helpdesk.db")


def db() -> sqlite3.Connection:
    conn = sqlite3.connect(DB_PATH, check_same_thread=False)
    conn.execute(
        """
        CREATE TABLE IF NOT EXISTS tickets (
          ticket_id TEXT PRIMARY KEY,
          created_at TEXT NOT NULL,
          category TEXT NOT NULL,
          urgency TEXT NOT NULL,
          summary TEXT NOT NULL,
          status TEXT NOT NULL
        )
        """
    )
    conn.execute(
        """
        CREATE TABLE IF NOT EXISTS metrics (
          key TEXT PRIMARY KEY,
          value INTEGER NOT NULL
        )
        """
    )
    conn.commit()
    return conn


def metric_get(key: str) -> int:
    conn = db()
    cur = conn.cursor()
    cur.execute("SELECT value FROM metrics WHERE key=?", (key,))
    row = cur.fetchone()
    return int(row[0]) if row else 0


def metric_bump(key: str, delta: int = 1) -> None:
    conn = db()
    cur = conn.cursor()
    cur.execute("SELECT value FROM metrics WHERE key=?", (key,))
    row = cur.fetchone()
    if row is None:
        cur.execute("INSERT INTO metrics(key, value) VALUES(?, ?)", (key, delta))
    else:
        cur.execute("UPDATE metrics SET value=? WHERE key=?", (row[0] + delta, key))
    conn.commit()


@dataclass
class Ticket:
    ticket_id: str
    created_at: str
    category: str
    urgency: str
    summary: str
    status: str


def now_str() -> str:
    return datetime.now().strftime("%Y-%m-%d %H:%M")


def new_ticket_id() -> str:
    return f"HD-{uuid.uuid4().hex[:8].upper()}"


def ticket_insert(t: Ticket) -> None:
    conn = db()
    conn.execute(
        """
        INSERT OR REPLACE INTO tickets(ticket_id, created_at, category, urgency, summary, status)
        VALUES(?, ?, ?, ?, ?, ?)
        """,
        (t.ticket_id, t.created_at, t.category, t.urgency, t.summary, t.status),
    )
    conn.commit()


def tickets_list(limit: int = 50) -> List[Ticket]:
    conn = db()
    cur = conn.cursor()
    cur.execute(
        """
        SELECT ticket_id, created_at, category, urgency, summary, status
        FROM tickets
        ORDER BY created_at DESC
        LIMIT ?
        """,
        (limit,),
    )
    rows = cur.fetchall()
    return [Ticket(*row) for row in rows]


def ticket_update_status(ticket_id: str, status: str) -> None:
    conn = db()
    conn.execute("UPDATE tickets SET status=? WHERE ticket_id=?", (status, ticket_id))
    conn.commit()


# ----------------------------
# Simple “intent” classifier (no LLM, no API)
# ----------------------------
def classify_category(text: str) -> str:
    t = text.lower()
    if any(k in t for k in ["password", "locked", "lockout", "reset", "login"]):
        return "Access / Password"
    if any(k in t for k in ["mfa", "2fa", "authenticator", "otp", "verification code"]):
        return "MFA / SSO"
    if any(k in t for k in ["vpn", "anyconnect", "globalprotect", "tunnel", "error 809"]):
        return "VPN"
    if any(k in t for k in ["wifi", "wi-fi", "wireless", "ssid"]):
        return "Wi‑Fi"
    if any(k in t for k in ["install", "software", "app", "license", "admin rights"]):
        return "Software"
    if any(k in t for k in ["printer", "print", "spool", "queue"]):
        return "Printer"
    if any(k in t for k in ["phish", "phishing", "suspicious email", "spam"]):
        return "Security (Phishing)"
    return "General"


