def context_line() -> str:
    p = st.session_state.profile
    bits = []
    if p.get("device"):
        bits.append(f"Device={p['device']}")
    if p.get("os"):
        bits.append(f"OS={p['os']}")
    if p.get("location"):
        bits.append(f"Location={p['location']}")
    return ", ".join(bits)


def assistant_typing(delay_s: float = 0.18) -> None:
    with st.chat_message("assistant"):
        ph = st.empty()
        for dots in ["", ".", "..", "..."]:
            ph.markdown(f"Thinking{dots}")
            time.sleep(delay_s)
        ph.empty()


def quick_steps(category: str) -> str:
    if category == "VPN":
        return "Try: 1) confirm internet works, 2) restart VPN client, 3) try hotspot vs Wi‑Fi."
    if category == "Wi‑Fi":
        return "Try: 1) forget network, 2) rejoin correct SSID, 3) restart laptop Wi‑Fi."
    if category == "Access / Password":
        return "Try: 1) reset password (if allowed), 2) wait 10–15 min if locked, 3) check caps/keyboard."
    if category == "MFA / SSO":
        return "Try: 1) check phone time, 2) switch MFA method, 3) re-enroll if new phone."
    if category == "Software":
        return "Try: 1) check software portal, 2) note app name/version, 3) request install approval if needed."
    if category == "Printer":
        return "Try: 1) power-cycle printer, 2) clear queue, 3) re-add printer if offline."
    if category == "Security (Phishing)":
        return "Do: 1) don’t click, 2) report via phishing workflow, 3) reset password if you entered it."
    return "Tell me the exact error text and what changed recently."


def create_ticket(summary: str, urgency: str) -> Ticket:
    category = classify_category(summary)
    ctx = context_line()
    full_summary = summary.strip()
    if ctx:
        full_summary = f"{full_summary} | {ctx}"

    t = Ticket(
        ticket_id=new_ticket_id(),
        created_at=now_str(),
        category=category,
        urgency=urgency,
        summary=full_summary[:450],
        status="Open",
    )
    ticket_insert(t)
    metric_bump("tickets", 1)
    return t


