with tab_chat:
    st.markdown("<div class='small-muted'>Quick actions</div>", unsafe_allow_html=True)
    c1, c2, c3, c4, c5 = st.columns(5)
    quick = [
        ("🔐 Login", "Access / Password"),
        ("🛡️ VPN", "VPN"),
        ("📶 Wi‑Fi", "Wi‑Fi"),
        ("🧩 Software", "Software"),
        ("🎣 Phishing", "Security (Phishing)"),
    ]
    clicked: Optional[str] = None
    for (label, cat), col in zip(quick, [c1, c2, c3, c4, c5]):
        if col.button(label, use_container_width=True):
            clicked = cat

    if clicked:
        st.session_state.messages.append({"role": "user", "content": f"[Quick action] {clicked}"})
        assistant_typing()
        st.session_state.messages.append(
            {
                "role": "assistant",
                "content": f"Got it: **{clicked}**.\n\n{quick_steps(clicked)}\n\nIf you’re still blocked, type **create ticket**.",
            }
        )
        metric_bump("contained", 1)
        st.rerun()

    st.divider()

    for m in st.session_state.messages:
        with st.chat_message(m["role"]):
            st.markdown(m["content"])

    user_text = st.chat_input("Describe your issue… (e.g., “VPN error 809 on Windows”)")
    if user_text:
        st.session_state.messages.append({"role": "user", "content": user_text})
        lower = user_text.lower().strip()

        # Ticket creation command opens a tiny form
        if lower.startswith("create ticket"):
            with st.chat_message("assistant"):
                st.markdown("Let’s create a ticket — quick and clean:")
                urgency = st.radio("Urgency", ["low", "med", "high"], horizontal=True, index=1)
                summary = st.text_area(
                    "Summary (one sentence)",
                    placeholder="e.g., VPN error 809 when connecting from home Wi‑Fi",
                )
                col_a, col_b = st.columns(2)
                with col_a:
                    confirm = st.button("🎫 Create ticket", type="primary", use_container_width=True)
                with col_b:
                    cancel = st.button("Cancel", use_container_width=True)

            if cancel:
                st.session_state.messages.append({"role": "assistant", "content": "No problem—tell me what you’re seeing and I’ll help."})
                st.rerun()

            if confirm:
                # If summary blank, use last user message (non-command)
                seed = summary.strip()
                if not seed:
                    for msg in reversed(st.session_state.messages):
                        if msg["role"] == "user" and not msg["content"].lower().strip().startswith("create ticket"):
                            seed = msg["content"]
                            break
                if not seed:
                    seed = "General help needed"

                t = create_ticket(seed, urgency)
                st.session_state.messages.append(
                    {
                        "role": "assistant",
                        "content": (
                            f"Done! Ticket **{t.ticket_id}** created 🎉\n\n"
                            f"- Category: **{t.category}**\n"
                            f"- Urgency: **{t.urgency}**\n"
                            f"- Status: **{t.status}**\n\n"
                            "If you paste the exact error text, I’ll add next steps."
                        ),
                    }
                )
                st.balloons()
                st.rerun()

        else:
            assistant_typing()
            cat = classify_category(user_text)
            st.session_state.messages.append(
                {
                    "role": "assistant",
                    "content": (
                        f"This looks like **{cat}**.\n\n{quick_steps(cat)}\n\n"
                        "If you want me to file it, type **create ticket**."
                    ),
                }
            )
            metric_bump("contained", 1)
            st.rerun()


